// lame.min.js — Auto-loader/cache pour lamejs
// Si le vrai lamejs est déjà chargé, ne rien faire
if (!window.lamejs) {
  (function() {
    var CDN = 'https://cdnjs.cloudflare.com/ajax/libs/lamejs/1.2.1/lame.min.js';
    var IDB_KEY = 'lamejs_cached_src';

    function execScript(src) {
      try { (0, eval)(src); } catch(e) { console.error('[lame loader] eval failed:', e); }
    }

    function loadFromNetwork(cb) {
      fetch(CDN, { cache: 'force-cache' })
        .then(function(r) { return r.text(); })
        .then(function(src) {
          execScript(src);
          // Mettre en cache dans IndexedDB pour usage hors-ligne
          try {
            var req = indexedDB.open('lamejs_cache', 1);
            req.onupgradeneeded = function(e) { e.target.result.createObjectStore('kv'); };
            req.onsuccess = function(e) {
              var db = e.target.result;
              db.transaction('kv','readwrite').objectStore('kv').put(src, IDB_KEY);
            };
          } catch(e) {}
          if (cb) cb();
        })
        .catch(function(err) {
          console.warn('[lame loader] CDN failed:', err);
          if (cb) cb(err);
        });
    }

    // Essayer IndexedDB d'abord (hors-ligne)
    try {
      var req = indexedDB.open('lamejs_cache', 1);
      req.onupgradeneeded = function(e) { e.target.result.createObjectStore('kv'); };
      req.onsuccess = function(e) {
        var db = e.target.result;
        var get = db.transaction('kv','readonly').objectStore('kv').get(IDB_KEY);
        get.onsuccess = function() {
          if (get.result) {
            execScript(get.result); // Hors-ligne : exécuter depuis cache
          } else {
            loadFromNetwork(); // Première fois : fetch + cache
          }
        };
        get.onerror = function() { loadFromNetwork(); };
      };
      req.onerror = function() { loadFromNetwork(); };
    } catch(e) {
      loadFromNetwork();
    }
  })();
}
